const updateActivityRecordingURL = `-- name: UpdateActivityRecordingURL :exec
UPDATE "Activity"
SET recording_url = $2,
    updated_at    = now()
WHERE zoom_call_id = $1
`

type UpdateActivityRecordingURLParams struct {
	ZoomCallID   pgtype.Text `json:"zoom_call_id"`
	RecordingUrl pgtype.Text `json:"recording_url"`
}

// phone.recording_completed イベントで recording archive 完了後に呼ぶ。
// $1 = zoom_call_id (= 既存 Activity row の dedup キー)
// $2 = recording の新パス (s3://phox-recordings/calls/.../recording.m4a)
func (q *Queries) UpdateActivityRecordingURL(ctx context.Context, arg UpdateActivityRecordingURLParams) error {
	_, err := q.db.Exec(ctx, updateActivityRecordingURL, arg.ZoomCallID, arg.RecordingUrl)
	return err
}

